// OpenCL Error Handling
const char *getErrorString(cl_int error) {
    switch (error) {
        // run-time and JIT compiler errors
        case 0: return "CL_SUCCESS";
        case -1: return "CL_DEVICE_NOT_FOUND";
        case -2: return "CL_DEVICE_NOT_AVAILABLE";
        case -3: return "CL_COMPILER_NOT_AVAILABLE";
        case -4: return "CL_MEM_OBJECT_ALLOCATION_FAILURE";
        case -5: return "CL_OUT_OF_RESOURCES";
        case -6: return "CL_OUT_OF_HOST_MEMORY";
        case -7: return "CL_PROFILING_INFO_NOT_AVAILABLE";
        case -8: return "CL_MEM_COPY_OVERLAP";
        case -9: return "CL_IMAGE_FORMAT_MISMATCH";
        case -10: return "CL_IMAGE_FORMAT_NOT_SUPPORTED";
        case -11: return "CL_BUILD_PROGRAM_FAILURE";
        case -12: return "CL_MAP_FAILURE";
        case -13: return "CL_MISALIGNED_SUB_BUFFER_OFFSET";
        case -14: return "CL_EXEC_STATUS_ERROR_FOR_EVENTS_IN_WAIT_LIST";
        case -15: return "CL_COMPILE_PROGRAM_FAILURE";
        case -16: return "CL_LINKER_NOT_AVAILABLE";
        case -17: return "CL_LINK_PROGRAM_FAILURE";
        case -18: return "CL_DEVICE_PARTITION_FAILED";
        case -19: return "CL_KERNEL_ARG_INFO_NOT_AVAILABLE";

        // compile-time errors
        case -30: return "CL_INVALID_VALUE";
        case -31: return "CL_INVALID_DEVICE_TYPE";
        case -32: return "CL_INVALID_PLATFORM";
        case -33: return "CL_INVALID_DEVICE";
        case -34: return "CL_INVALID_CONTEXT";
        case -35: return "CL_INVALID_QUEUE_PROPERTIES";
        case -36: return "CL_INVALID_COMMAND_QUEUE";
        case -37: return "CL_INVALID_HOST_PTR";
        case -38: return "CL_INVALID_MEM_OBJECT";
        case -39: return "CL_INVALID_IMAGE_FORMAT_DESCRIPTOR";
        case -40: return "CL_INVALID_IMAGE_SIZE";
        case -41: return "CL_INVALID_SAMPLER";
        case -42: return "CL_INVALID_BINARY";
        case -43: return "CL_INVALID_BUILD_OPTIONS";
        case -44: return "CL_INVALID_PROGRAM";
        case -45: return "CL_INVALID_PROGRAM_EXECUTABLE";
        case -46: return "CL_INVALID_KERNEL_NAME";
        case -47: return "CL_INVALID_KERNEL_DEFINITION";
        case -48: return "CL_INVALID_KERNEL";
        case -49: return "CL_INVALID_ARG_INDEX";
        case -50: return "CL_INVALID_ARG_VALUE";
        case -51: return "CL_INVALID_ARG_SIZE";
        case -52: return "CL_INVALID_KERNEL_ARGS";
        case -53: return "CL_INVALID_WORK_DIMENSION";
        case -54: return "CL_INVALID_WORK_GROUP_SIZE";
        case -55: return "CL_INVALID_WORK_ITEM_SIZE";
        case -56: return "CL_INVALID_GLOBAL_OFFSET";
        case -57: return "CL_INVALID_EVENT_WAIT_LIST";
        case -58: return "CL_INVALID_EVENT";
        case -59: return "CL_INVALID_OPERATION";
        case -60: return "CL_INVALID_GL_OBJECT";
        case -61: return "CL_INVALID_BUFFER_SIZE";
        case -62: return "CL_INVALID_MIP_LEVEL";
        case -63: return "CL_INVALID_GLOBAL_WORK_SIZE";
        case -64: return "CL_INVALID_PROPERTY";
        case -65: return "CL_INVALID_IMAGE_DESCRIPTOR";
        case -66: return "CL_INVALID_COMPILER_OPTIONS";
        case -67: return "CL_INVALID_LINKER_OPTIONS";
        case -68: return "CL_INVALID_DEVICE_PARTITION_COUNT";

        // extension errors
        case -1000: return "CL_INVALID_GL_SHAREGROUP_REFERENCE_KHR";
        case -1001: return "CL_PLATFORM_NOT_FOUND_KHR";
        case -1002: return "CL_INVALID_D3D10_DEVICE_KHR";
        case -1003: return "CL_INVALID_D3D10_RESOURCE_KHR";
        case -1004: return "CL_D3D10_RESOURCE_ALREADY_ACQUIRED_KHR";
        case -1005: return "CL_D3D10_RESOURCE_NOT_ACQUIRED_KHR";
        default: return "Unknown OpenCL error";
    }
}

void check(cl_int error) {
    if (error != 0) {
        fprintf(stderr, "OpenCL Error: %s (%d)\n", getErrorString(error), error);
        exit(EXIT_FAILURE);
    }
}

void printCompilerError(cl_program program, cl_device_id device) {
    cl_int status;
    size_t logSize;
    char *log;

    status = clGetProgramBuildInfo(program, device, CL_PROGRAM_BUILD_LOG, 0, NULL, &logSize);
    check(status);

    if (logSize > 1) { // Only print if there's an actual log message
        log = (char *) malloc(logSize);
        if (!log) {
            fprintf(stderr, "Failed to allocate memory for build log.\n");
            exit(EXIT_FAILURE);
        }

        status = clGetProgramBuildInfo(program, device, CL_PROGRAM_BUILD_LOG, logSize, log, NULL);
        check(status);

        fprintf(stderr, "OpenCL Build Log:\n%s\n", log);
        free(log);
    }
}

void print_single_info(cl_platform_id platform, cl_device_id device) {
    char *value;
    size_t valueSize;
    cl_uint maxComputeUnits;

    // print device name
    clGetDeviceInfo(device, CL_DEVICE_NAME, 0, NULL, &valueSize);
    value = (char *) malloc(valueSize);
    clGetDeviceInfo(device, CL_DEVICE_NAME, valueSize, value, NULL);
    printf("Device Name: %s\n", value);
    free(value);

    // print hardware device version
    clGetDeviceInfo(device, CL_DEVICE_VERSION, 0, NULL, &valueSize);
    value = (char *) malloc(valueSize);
    clGetDeviceInfo(device, CL_DEVICE_VERSION, valueSize, value, NULL);
    printf("  Hardware version: %s\n", value);
    free(value);

    // print software driver version
    clGetDeviceInfo(device, CL_DRIVER_VERSION, 0, NULL, &valueSize);
    value = (char *) malloc(valueSize);
    clGetDeviceInfo(device, CL_DRIVER_VERSION, valueSize, value, NULL);
    printf("  Software version: %s\n", value);
    free(value);

    // print c version supported by compiler for device
    clGetDeviceInfo(device, CL_DEVICE_OPENCL_C_VERSION, 0, NULL, &valueSize);
    value = (char *) malloc(valueSize);
    clGetDeviceInfo(device, CL_DEVICE_OPENCL_C_VERSION, valueSize, value, NULL);
    printf("  OpenCL C version: %s\n", value);
    free(value);

    // print parallel compute units
    clGetDeviceInfo(device, CL_DEVICE_MAX_COMPUTE_UNITS, sizeof(maxComputeUnits), &maxComputeUnits, NULL);
    printf("  Parallel compute units: %d\n", maxComputeUnits);
}

void print_opencl_info(void) {
    cl_uint platformCount;
    cl_platform_id *platforms;
    cl_uint deviceCount;
    cl_device_id *devices;
    cl_uint maxComputeUnits;
    char *value;
    size_t valueSize;
    int i, j;

    // Get number of platforms
    cl_int ret = clGetPlatformIDs(0, NULL, &platformCount);
    check(ret);
    printf("Number of OpenCL platforms detected: %d\n", platformCount);

    if (platformCount == 0) {
        printf("No OpenCL platforms found.\n");
        return;
    }

    // Allocate space for platform IDs
    platforms = (cl_platform_id *) malloc(platformCount * sizeof(cl_platform_id));
    ret = clGetPlatformIDs(platformCount, platforms, NULL);
    check(ret);

    // Iterate over platforms
    for (i = 0; i < platformCount; i++) {
        char platformName[100];
        ret = clGetPlatformInfo(platforms[i], CL_PLATFORM_NAME, sizeof(platformName), platformName, NULL);
        check(ret);
        printf("\nPlatform %d: %s\n", i, platformName);

        // Get number of devices for the current platform
        ret = clGetDeviceIDs(platforms[i], CL_DEVICE_TYPE_ALL, 0, NULL, &deviceCount);
        if (ret == CL_DEVICE_NOT_FOUND) {
            printf("  No OpenCL devices found for this platform.\n");
            continue;
        }
        check(ret);
        printf("  Number of devices found: %d\n", deviceCount);

        // Allocate space for device IDs
        devices = (cl_device_id *) malloc(deviceCount * sizeof(cl_device_id));
        ret = clGetDeviceIDs(platforms[i], CL_DEVICE_TYPE_ALL, deviceCount, devices, NULL);
        check(ret);

        // Iterate over devices
        for (j = 0; j < deviceCount; j++) {
            printf("  Device %d:\n", j);
            print_single_info(platforms[i], devices[j]);
        }
        free(devices);
    }
    free(platforms);
}

OpenCLInfo initialize_device(int user_platform_id, int user_device_id) {
    border_print();
    center_print("AVAILABLE OPENCL PLATFORMS & DEVICES", 79);
    border_print();
    print_opencl_info();
    border_print();

    center_print("DEVICE INITIALIZATION", 79);
    border_print();

    cl_platform_id target_platform_id = NULL;
    cl_device_id device_id = NULL;
    cl_int ret;

    // Get platform count
    cl_uint platformCount;
    ret = clGetPlatformIDs(0, NULL, &platformCount);
    check(ret);

    if (platformCount == 0) {
        fprintf(stderr, "No OpenCL platforms found.\n");
        exit(EXIT_FAILURE);
    }

    // Allocate space for platform IDs
    cl_platform_id *platforms = (cl_platform_id *) malloc(platformCount * sizeof(cl_platform_id));
    ret = clGetPlatformIDs(platformCount, platforms, NULL);
    check(ret);

    // Select platform
    int platform_idx = (user_platform_id != -1) ? user_platform_id : 0;
    if (platform_idx >= platformCount) {
        fprintf(stderr, "Invalid platform ID specified: %d. Must be between 0 and %d.\n", user_platform_id, platformCount - 1);
        exit(EXIT_FAILURE);
    }
    target_platform_id = platforms[platform_idx];
    free(platforms);

    // Get device count for the selected platform
    cl_uint deviceCount;
    ret = clGetDeviceIDs(target_platform_id, CL_DEVICE_TYPE_ALL, 0, NULL, &deviceCount);
    if (ret == CL_DEVICE_NOT_FOUND) {
        fprintf(stderr, "No OpenCL devices found for the selected platform.\n");
        exit(EXIT_FAILURE);
    }
    check(ret);

    // Select device
    int device_idx = (user_device_id != -1) ? user_device_id : 0;
    if (device_idx >= deviceCount) {
        fprintf(stderr, "Invalid device ID specified: %d. Must be between 0 and %d for the selected platform.\n", user_device_id, deviceCount - 1);
        exit(EXIT_FAILURE);
    }

    cl_device_id *devices = (cl_device_id *) malloc(deviceCount * sizeof(cl_device_id));
    ret = clGetDeviceIDs(target_platform_id, CL_DEVICE_TYPE_ALL, deviceCount, devices, NULL);
    check(ret);
    device_id = devices[device_idx];
    free(devices);

    // Print info about the selected device
    printf("Selected OpenCL Device:\n");
    printf("  Platform ID: %d\n", platform_idx);
    printf("  Device ID:   %d\n", device_idx);
    print_single_info(target_platform_id, device_id);
    printf("Note: Platform ID can be specified with the \"-P\" flag and Device ID with the \"-D\" flag.\n");

    // Create an OpenCL context
    cl_context context = clCreateContext(NULL, 1, &device_id, NULL, NULL, &ret);
    check(ret);

    // Create a command queue
    cl_command_queue command_queue = clCreateCommandQueue(context, device_id, 0, &ret);
    check(ret);

    OpenCLInfo CL;
    CL.platform_id = target_platform_id;
    CL.device_id = device_id;
    CL.context = context;
    CL.command_queue = command_queue;
    return CL;
}

cl_mem copy_array_to_device(OpenCLInfo * CL, cl_mem_flags mem_flags, void * array, size_t sz) {
    cl_int ret;
    cl_mem d_array = clCreateBuffer(CL->context, mem_flags, sz, NULL, &ret);
    check(ret);
    ret = clEnqueueWriteBuffer(CL->command_queue, d_array, CL_TRUE, 0, sz, array, 0, NULL, NULL);
    check(ret);
    return d_array;
}

void copy_array_from_device(OpenCLInfo * CL, cl_mem * d_array, void * h_array, size_t sz) {
    cl_int ret;
    ret = clEnqueueReadBuffer(CL->command_queue, *d_array, CL_TRUE, 0, sz, h_array, 0, NULL, NULL);
    check(ret);
}

void set_kernel_arguments(cl_kernel * kernel, int argc, size_t * arg_sz, void ** args) {
    cl_int ret;
    for (int i = 0; i < argc; i++) {
        ret = clSetKernelArg(*kernel, i, arg_sz[i], args[i]);
        check(ret);
    }
}

cl_kernel compile_kernel(OpenCLInfo * CL, char * kernel_name) {
    printf("Compiling OpenCL kernel: %s...\n", kernel_name);

    FILE *fp;
    char *source_str;
    size_t source_size;
    char kernel_fname[256];

    sprintf(kernel_fname, "%s.cl", kernel_name);

    fp = fopen(kernel_fname, "r");
    if (!fp) {
        fprintf(stderr, "Failed to load kernel file: %s\n", kernel_fname);
        exit(EXIT_FAILURE);
    }
    source_str = (char *) malloc(MAX_SOURCE_SIZE);
    if (!source_str) {
        fprintf(stderr, "Failed to allocate memory for kernel source.\n");
        fclose(fp);
        exit(EXIT_FAILURE);
    }
    source_size = fread(source_str, 1, MAX_SOURCE_SIZE, fp);
    if (source_size == 0) {
        fprintf(stderr, "Failed to read kernel source file: %s\n", kernel_fname);
        fclose(fp);
        free(source_str);
        exit(EXIT_FAILURE);
    }
    fclose(fp);

    cl_int ret;
    cl_program program = clCreateProgramWithSource(CL->context, 1, (const char **)&source_str, (const size_t *)&source_size, &ret);
    check(ret);
    free(source_str); // Free source string after program creation

    // Build the program
    ret = clBuildProgram(program, 1, &CL->device_id, NULL, NULL, NULL);
    check(ret);

    printCompilerError(program, CL->device_id);

    // Create the OpenCL kernel
    cl_kernel kernel = clCreateKernel(program, kernel_name, &ret);
    check(ret);

    return kernel;
}

void clear_array(OpenCLInfo * CL, cl_mem * buffer, size_t sz) {
    // Using 0.0f for float, adjust if using doubles or other types
    float fill_value = 0.0f;
    cl_int ret = clEnqueueFillBuffer(
        CL->command_queue,
        *buffer,
        &fill_value,
        sizeof(float),
        0,
        sz,
        0,
        NULL,
        NULL);
    check(ret);
}
